import React, { useEffect, useState } from 'react';
import { Grid, CircularProgress } from '@material-ui/core';
import { useSelector } from 'react-redux';
import { useLocation, Navigate } from 'react-router-dom';
import AddNewPlayer from '../Players/Player/AddNewPlayer';
import Player from './Player/Player';
import useStyles from './styles';
import { useAuth } from '../Auth/AuthContext';

const Players = () => {
  const { isLoading, players } = useSelector((state) => state.players);
  const classes = useStyles();
  const [filteredPlayers, setFilteredPlayers] = useState([]);
  const { search } = useLocation();
  const isAuthenticated = useAuth().isAuthenticated;

  useEffect(() => {
    console.log("Search query:", search);
  
    const params = new URLSearchParams(search);
    const searchQuery = params.get('searchQuery');
    console.log("Search query value:", searchQuery);
  
    if (searchQuery) {
      const [category, subCategory] = searchQuery.split(',');
      console.log("Category:", category);
      console.log("Subcategory:", subCategory);
  
      const filtered = players.filter(player => player.category.includes(category) && player.subCategory.includes(subCategory));
      console.log("Filtered players:", filtered);
  
      setFilteredPlayers(filtered);
  
      // Om inga matchande spelare hittades, gör en omdirigering till 404-sidan
      if (filtered.length === 0) {
        console.log("No matching players found. Redirecting to 404 page.");
        return <Navigate to="/404" />;
      }
    } else {
      // Om sökfrågan inte finns, visa alla spelare
      console.log("No search query. Showing all players.");
      setFilteredPlayers(players);
    }
  }, [search, players, navigate]);
  
  

  if (isLoading) {
    return <CircularProgress />;
  }

  // Kontrollera om det finns några filtrerade spelare, om inte, dirigera till 404-sidan
  if (!isLoading && !filteredPlayers.length) {
    return <Navigate to="/404" />;
  }

  return (
    <Grid container alignItems="stretch" spacing={3}>
      {filteredPlayers.map((player) => (
        <Grid key={player._id} item xs={12} sm={6} md={4}>
          <Player player={player} />
        </Grid>
      ))}
      {isAuthenticated && (
        <AddNewPlayer />
      )}
    </Grid>
  );
};

export default Players;
